# File: complex_data_processor.py
# This module handles high-volume data ingestion, transformation, and validation.

import os
import json
import logging
from datetime import datetime
from typing import List, Dict, Any, Optional

logging.basicConfig(level=logging.INFO, format='%(asctime)s - %(levelname)s - %(message)s')

class DataSchemaError(Exception):
    """Custom exception for schema validation errors."""
    pass

class DataProcessor:
    def __init__(self, config_path: str = 'config.json'):
        self.config = self._load_config(config_path)
        self.schema = self._load_schema(self.config['schema_file'])
        self.buffer_size = self.config.get('buffer_size', 1000)
        self.data_buffer = []
        logging.info(f"DataProcessor initialized with config from {config_path}")

    def _load_config(self, config_path: str) -> Dict[str, Any]:
        if not os.path.exists(config_path):
            logging.error(f"Config file not found at {config_path}")
            raise FileNotFoundError(f"Config file not found: {config_path}")
        with open(config_path, 'r', encoding='utf-8') as f:
            return json.load(f)

    def _load_schema(self, schema_file: str) -> Dict[str, Any]:
        schema_path = os.path.join(self.config['schema_dir'], schema_file)
        if not os.path.exists(schema_path):
            logging.error(f"Schema file not found at {schema_path}")
            raise FileNotFoundError(f"Schema file not found: {schema_path}")
        with open(schema_path, 'r', encoding='utf-8') as f:
            return json.load(f)

    def _validate_record(self, record: Dict[str, Any]) -> bool:
        """Validates a single data record against the loaded schema."""
        for field, rules in self.schema['fields'].items():
            if rules.get('required') and field not in record:
                logging.warning(f"Missing required field: {field} in record {record.get('id')}")
                return False
            if field in record:
                value = record[field]
                if 'type' in rules and not isinstance(value, eval(rules['type'])):
                    logging.warning(f"Type mismatch for field {field}: expected {rules['type']}, got {type(value)}")
                    return False
                if 'min_length' in rules and len(str(value)) < rules['min_length']:
                    logging.warning(f"Length constraint violation for field {field}")
                    return False
                if 'max_length' in rules and len(str(value)) > rules['max_length']:
                    logging.warning(f"Length constraint violation for field {field}")
                    return False
                if 'enum' in rules and value not in rules['enum']:
                    logging.warning(f"Enum constraint violation for field {field}")
                    return False
        return True

    def _transform_record(self, record: Dict[str, Any]) -> Dict[str, Any]:
        """Applies various transformations to a record."""
        transformed = record.copy()
        if 'timestamp' in transformed and isinstance(transformed['timestamp'], (int, float)):
            transformed['processed_at'] = datetime.fromtimestamp(transformed['timestamp']).isoformat()
        if 'name' in transformed and isinstance(transformed['name'], str):
            transformed['name'] = transformed['name'].strip().title()
        # Simulate a complex, conditional transformation based on other fields
        if transformed.get('status') == 'pending' and transformed.get('priority', 0) > 5:
            transformed['action_required'] = True
        return transformed

    def ingest_data(self, raw_data: List[Dict[str, Any]]) -> List[Dict[str, Any]]:
        """Ingests a batch of raw data, validates, transforms, and buffers it."""
        processed_batch = []
        for record in raw_data:
            if self._validate_record(record):
                transformed_record = self._transform_record(record)
                self.data_buffer.append(transformed_record)
                processed_batch.append(transformed_record)
                if len(self.data_buffer) >= self.buffer_size:
                    self._flush_buffer()
            else:
                logging.error(f"Record failed validation: {record.get('id', 'N/A')}")
        return processed_batch

    def _flush_buffer(self):
        """Simulates writing the buffered data to a persistent store."""
        logging.info(f"Flushing {len(self.data_buffer)} records from buffer.")
        # In a real scenario, this would write to a DB, file, or send to another service
        # For simulation, we just clear the buffer.
        self.data_buffer.clear()

    def get_processed_count(self) -> int:
        """Returns the count of records currently in the buffer."""
        return len(self.data_buffer)

    def close(self):
        """Cleans up resources and flushes any remaining data."""
        if self.data_buffer:
            self._flush_buffer()
        logging.info("DataProcessor closed.")

# Example Usage (not part of the main module, for testing)
if __name__ == '__main__':
