    # For brevity, these are not included but would be large JSON files.
    # config.json: {"schema_file": "data_schema.json", "schema_dir": ".", "buffer_size": 5}
    # data_schema.json: {"fields": {"id": {"type": "str", "required": true}, "name": {"type": "str", "max_length": 100}, "age": {"type": "int", "min": 0}, "status": {"type": "str", "enum": ["active", "pending", "rejected"]}}}

    processor = DataProcessor()
    sample_data = [
        {"id": "rec1", "name": "  Alice  ", "age": 30, "status": "active", "timestamp": 1678886400},
        {"id": "rec2", "name": "Bob", "age": 25, "status": "pending", "priority": 7, "timestamp": 1678886500},
        {"id": "rec3", "name": "Charlie", "age": -5, "status": "active", "timestamp": 1678886600}, # Invalid age
        {"id": "rec4", "name": 123, "age": 40, "status": "rejected", "timestamp": 1678886700}, # Invalid name type
        {"id": "rec5", "name": "David", "age": 35, "status": "unknown", "timestamp": 1678886800}, # Invalid status enum
        {"id": "rec6", "name": "Eve", "age": 28, "status": "active", "timestamp": 1678886900}
    ]

    processed = processor.ingest_data(sample_data)
    logging.info(f"Processed records: {len(processed)}")
    logging.info(f"Buffer count after ingestion: {processor.get_processed_count()}")

    processor.close()
